import{_ as a,c as t,o as r,ag as i}from"./chunks/framework.S-Qvb3wi.js";const f=JSON.parse('{"title":"Academic Research Support","description":"","frontmatter":{},"headers":[],"relativePath":"Academic-Research.md","filePath":"Academic-Research.md"}'),n={name:"Academic-Research.md"};function o(s,e,c,d,l,h){return r(),t("div",null,e[0]||(e[0]=[i('<h1 id="academic-research-support" tabindex="-1">Academic Research Support <a class="header-anchor" href="#academic-research-support" aria-label="Permalink to &quot;Academic Research Support&quot;">​</a></h1><p>The design logic, technical feasibility, and performance advantages of the aforementioned PoQ mechanism have been validated through dedicated academic research. For detailed insights, refer to the following papers:</p><ol><li><a href="https://arxiv.org/abs/2512.16317" target="_blank" rel="noreferrer"><em>Design and Evaluation of Cost-Aware PoQ for Decentralized LLM Inference</em></a>: Proposes a cost-aware PoQ framework that integrates efficiency metrics into incentive mechanisms. It achieves dynamic balance between quality and cost through a unified evaluation pipeline, verifying the practicality and economic sustainability of the multi-dimensional evaluation system.</li><li><a href="https://arxiv.org/abs/2512.20176" target="_blank" rel="noreferrer"><em>Optimistic TEE-Rollups: A Hybrid Architecture for Scalable and Verifiable Generative AI Inference on Blockchain</em></a>: Presents a hybrid verification protocol that provides the underlying architecture for on-chain verifiable proofs. By combining Trusted Execution Environments (TEE) with zero-knowledge spot checks, it resolves the trilemma of verifiability in decentralized inference and further enhances the security and efficiency of PoQ proofs.</li><li><a href="https://arxiv.org/html/2601.21189v1" target="_blank" rel="noreferrer"><em>Adaptive and Robust Cost-Aware Proof of Quality for Decentralized LLM Inference Networks</em></a>: Extends the cost-aware PoQ mechanism with adversary-resilient consensus formation, integrating robust aggregation rules (median, trimmed mean) and an adaptive trust-weighted consensus strategy that updates evaluator weights based on deviation signals. Through experiments on question answering and summarization tasks with four adversarial attack strategies, it verifies that robust aggregation improves the alignment of consensus scores with ground truth proxies and reduces sensitivity to noisy and strategic attacks, while also clarifying the operational trade-offs between evaluator sampling size, robustness, reward variance and evaluation overhead, providing practical guidance for PoQ deployment under adversarial risks and resource constraints.</li></ol>',3)]))}const u=a(n,[["render",o]]);export{f as __pageData,u as default};
